import{_ as a,o as t,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Amazon","description":"","frontmatter":{"title":"Amazon","slug":"amazon-san"},"headers":[],"relativePath":"marketer-hub/amazon-san.md","filePath":"marketer-hub/amazon-san.md"}'),o={name:"marketer-hub/amazon-san.md"};function i(s,e,d,l,c,p){return t(),r("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Amazon SAN (Self-Attributing Network) is Branch’s integration with Amazon Ads, and it enables you to measure and attribute app installs and in-app events from your Amazon DSP campaigns.</p><p>This integration uses Amazon’s Events Manager to pass conversion data in real-time, allowing you to:</p><ul><li>Track mobile app installs and in-app conversions.</li><li>Attribute user actions back to Amazon advertising campaigns.</li><li>Optimize campaigns based on cost per install (CPI), cost per action (CPA), and return on ad spend (ROAS).</li><li>Create custom audiences based on app conversion signals.</li></ul><p>For more information about Amazon&#39;s Events Manager and MMP integration, visit Amazon’s <a href="https://advertising.amazon.com/help/GF97FJUFXBDM32P4" target="_blank" rel="noreferrer">help documentation</a>.</p><h3 id="platform-support" tabindex="-1">Platform support <a class="header-anchor" href="#platform-support" aria-label="Permalink to &quot;Platform support&quot;">​</a></h3><p>Amazon SAN integration supports:</p><ul><li>Android mobile devices</li><li>Amazon Fire TV devices</li><li>Amazon Fire Tablet devices</li><li>iOS devices (via SKAdNetwork)</li></ul><h4 id="ios-attribution-with-skan" tabindex="-1">iOS attribution with SKAN <a class="header-anchor" href="#ios-attribution-with-skan" aria-label="Permalink to &quot;iOS attribution with SKAN&quot;">​</a></h4><p>iOS campaigns are supported through Amazon’s integration with Apple’s SKAdNetwork (SKAN). While Android and Amazon Fire devices use Amazon’s direct SAN integration, iOS attribution works through SKAN to comply with Apple’s privacy requirements.</p><p>SKAN is more limited than the direct SAN integration, so expect to see more comprehensive attribution on Android and Amazon Fire devices than iOS devices.</p><p>Learn more in our <a href="https://help.branch.io/docs/skadnetwork" target="_blank" rel="noreferrer">SKAdNetwork documentation</a>.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ol><li><p>Branch setup requires:</p><ol><li><p>A Branch account.</p></li><li><p>The Performance product enabled for your account. Learn more on our <a href="https://help.branch.io/docs/products#performance" target="_blank" rel="noreferrer">Products page</a>, or <a href="https://branchdocs.app.link/e/amazon-contact-sales" target="_blank" rel="noreferrer">contact our Sales team</a>.</p></li><li><p>The Branch SDK integrated into your mobile app(s):</p><ol><li><a href="https://help.branch.io/developers-hub/docs/ios-basic-integration" target="_blank" rel="noreferrer">iOS</a></li><li><a href="https://help.branch.io/developers-hub/docs/android-basic-integration" target="_blank" rel="noreferrer">Android</a></li></ol></li></ol></li><li><p>Amazon setup requires:</p><ol><li>An Amazon Ads or Amazon DSP account.</li><li>Admin access to your Amazon Advertising console.</li><li>Access to your Amazon Advertiser ID (more information <a href="./amazon-new.html#step-2-enter-amazon-advertiser-id">below</a>).</li></ol></li></ol><h2 id="enable-amazon-san" tabindex="-1">Enable Amazon SAN <a class="header-anchor" href="#enable-amazon-san" aria-label="Permalink to &quot;Enable Amazon SAN&quot;">​</a></h2><h3 id="step-1-enable-amazon-san-in-branch" tabindex="-1">Step 1: Enable Amazon SAN in Branch <a class="header-anchor" href="#step-1-enable-amazon-san-in-branch" aria-label="Permalink to &quot;Step 1: Enable Amazon SAN in Branch&quot;">​</a></h3><ol><li>Visit the <a href="https://branchdocs.app.link/e/amazon-san-dashboard" target="_blank" rel="noreferrer"><strong>Ad Partners</strong> page</a> in Branch.</li><li>In the search bar, type <strong>Amazon SAN</strong> and select this option from the results.</li><li>Select <strong>Save &amp; Enable</strong>.</li></ol><h3 id="step-2-enter-amazon-advertiser-id" tabindex="-1">Step 2: Enter Amazon Advertiser ID <a class="header-anchor" href="#step-2-enter-amazon-advertiser-id" aria-label="Permalink to &quot;Step 2: Enter Amazon Advertiser ID&quot;">​</a></h3><p>Enter your Amazon Advertiser ID in Branch when prompted during setup.</p><h4 id="find-your-amazon-advertiser-id" tabindex="-1">Find your Amazon Advertiser ID <a class="header-anchor" href="#find-your-amazon-advertiser-id" aria-label="Permalink to &quot;Find your Amazon Advertiser ID&quot;">​</a></h4><p><strong>For self-service advertisers</strong>:</p><ol><li>Navigate to the Amazon Ads reporting console.</li><li>Look for your advertiser name in the <strong>Advertisers</strong> tab of the <strong>Amazon DSP Campaign Manager</strong>.</li><li>Copy your Advertiser ID from this location.</li></ol><p><strong>For managed service advertisers</strong>:</p><p>Managed service advertisers must contact their Amazon account manager to obtain their Amazon Advertiser ID.</p><h3 id="step-3-configure-event-mapping" tabindex="-1">Step 3: Configure event mapping <a class="header-anchor" href="#step-3-configure-event-mapping" aria-label="Permalink to &quot;Step 3: Configure event mapping&quot;">​</a></h3><ol><li><p>Navigate to the <a href="https://branchdocs.app.link/e/amazon-san-dashboard-event-config" target="_blank" rel="noreferrer"><strong>Event Config</strong> tab</a> in Branch’s Amazon SAN partner settings.</p></li><li><p>Enable the events you want to share with Amazon Ads by toggling them on.</p></li><li><p>Map your in-app events:</p><ol><li><p>In the left field, select the name of a <a href="https://help.branch.io/developers-hub/docs/track-branch-events#track-events" target="_blank" rel="noreferrer">Branch Event</a>. You can use Standard Events, which are predefined by Branch, or Custom Events, which are defined by you.</p><ol><li>Branch strongly recommends that you use Standard Events whenever possible.</li></ol></li><li><p>In the right field, map it to one of Amazon’s predefined conversion events.</p></li><li><p>Repeat this for all events you want to track with Amazon.</p></li></ol></li></ol><h4 id="standard-amazon-conversion-event-types" tabindex="-1">Standard Amazon conversion event types <a class="header-anchor" href="#standard-amazon-conversion-event-types" aria-label="Permalink to &quot;Standard Amazon conversion event types&quot;">​</a></h4><p>Amazon supports the following standard conversion event types for mapping:</p><table tabindex="0"><thead><tr><th>Amazon event name</th><th>Description</th><th>Branch options</th></tr></thead><tbody><tr><td><code>ADD_TO_SHOPPING_CART</code></td><td>When a user adds a product to their shopping cart.</td><td><code>ADD_TO_CART</code></td></tr><tr><td><code>APPLICATION</code></td><td>When a user submits an application.</td><td><code>COMPLETE_REGISTRATION</code> or Custom Event</td></tr><tr><td><code>CHECKOUT</code></td><td>When a user goes to the checkout page.</td><td><code>INITIATE_PURCHASE</code> or <code>PURCHASE</code></td></tr><tr><td><code>CONTACT</code></td><td>When a user supplies contact information, such as email, phone number, etc.</td><td>Custom Event</td></tr><tr><td><code>LEAD</code></td><td>When a user performs an action that initiates a sales lead.</td><td><code>COMPLETE_REGISTRATION</code> or Custom Event</td></tr><tr><td><code>OFF_AMAZON_PURCHASES</code></td><td>When a user makes a purchase for a service or product.</td><td><code>PURCHASE</code></td></tr><tr><td><code>PAGE_VIEW</code></td><td>When a user visits a page on your website.</td><td><code>VIEW_ITEM</code> or <code>VIEW_ITEMS</code></td></tr><tr><td><code>SEARCH</code></td><td>When a user performs a search for a product.</td><td><code>SEARCH</code></td></tr><tr><td><code>SIGN_UP</code></td><td>When a user signs up for a product or service.</td><td><code>COMPLETE_REGISTRATION</code></td></tr><tr><td><code>SUBSCRIBE</code></td><td>When a user signs up for your service.</td><td><code>SUBSCRIBE</code> or <code>START_TRIAL</code></td></tr><tr><td><code>OTHER</code></td><td>User events that don’t fit the definition of the standard conversion types.</td><td>Custom Event</td></tr><tr><td><code>MOBILE_APP_FIRST_START</code></td><td>When a user launches the mobile app for the first time.</td><td>Tracked by default by Branch SDK as <code>INSTALL</code></td></tr></tbody></table><p>For a full list of Branch Standard Events and how to track them, see <a href="https://help.branch.io/developers-hub/docs/track-branch-events" target="_blank" rel="noreferrer">Track Branch Events</a>.</p><p><strong>Important notes</strong>:</p><ul><li>Only events that are properly mapped will be sent to Amazon. Unmapped events will not be shared with Amazon Ads.</li><li>For Amazon events that don&#39;t have a direct Branch Standard Event equivalent (like <code>CONTACT</code> or <code>LEAD</code>), you can create a Custom Event with an appropriate name.</li><li>The <code>MOBILE_APP_FIRST_START</code> event is automatically tracked by the Branch SDK as an <code>INSTALL</code> event.</li></ul><h3 id="step-4-set-attribution-windows" tabindex="-1">Step 4: Set attribution windows <a class="header-anchor" href="#step-4-set-attribution-windows" aria-label="Permalink to &quot;Step 4: Set attribution windows&quot;">​</a></h3><ol><li><p>Navigate to the <a href="https://branchdocs.app.link/e/amazon-san-attribution-windows" target="_blank" rel="noreferrer">Attribution Windows tab</a> in Branch’s Amazon SAN partner settings.</p></li><li><p>Configure your attribution windows to match your campaign needs:</p><ol><li>Click-through attribution window: Time window after click during which conversions are attributed to Amazon.</li><li>View-through attribution window: Time window after an impression during which conversions are attributed to Amazon.</li></ol></li></ol><h2 id="data-sharing-and-privacy" tabindex="-1">Data sharing and privacy <a class="header-anchor" href="#data-sharing-and-privacy" aria-label="Permalink to &quot;Data sharing and privacy&quot;">​</a></h2><p>Amazon has specific data handling requirements that Branch adheres to:</p><ul><li>User-level data retention: Amazon user-level data is retained for attribution purposes according to Amazon’s policies.</li><li>Privacy protection: Amazon does not provide access to certain raw campaign data to protect end-user privacy.</li><li>Campaign details: When installs or events are attributed to Amazon, campaign details are available in Branch.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>What is Amazon SAN?</summary><p>Amazon SAN (Self-Attributing Network) is Branch’s integration with Amazon Ads that allows you to measure and attribute app installs and in-app events from your Amazon DSP campaigns.</p></details><details><summary>What platforms does Amazon SAN support?</summary><p>Amazon SAN integration supports Android mobile devices, Amazon Fire TV devices, and Amazon Fire Tablet devices. iOS campaigns are not supported.</p></details><details><summary>Do I need to create Branch Ad Links for Amazon campaigns?</summary><p>No, Amazon SAN does not require you to create Branch Ad Links for tracking Amazon campaigns as Amazon’s platform automatically handles tracking.</p></details><details><summary>What should I do if events are not showing up?</summary><p>If you don’t see the events you’re expecting:</p><ul><li>Verify event mapping is configured correctly.</li><li>Ensure the Branch SDK is properly implemented and events are being logged.</li><li>Check that postbacks are enabled for the events you want to share.</li><li>Confirm your Amazon Advertiser ID is entered correctly.</li></ul></details><details><summary>What should I do if I’m seeing attribution discrepancies?</summary><p>If you’re seeing attribution discrepancies between Amazon and Branch:</p><ul><li>Remember that Amazon is self-attributing and may have different attribution logic than Branch.</li><li>Check that the same events are being tracked consistently across both platforms.</li></ul></details><details><summary>Why is my campaign data not appearing?</summary><p>If your campaign data is not appearing as expected:</p><ul><li>Confirm Amazon SAN integration is enabled in Branch.</li><li>Verify you have active Amazon DSP campaigns running.</li><li>Allow up to 24 hours for initial data to populate.</li></ul></details>',44)])])}const u=a(o,[["render",i]]);export{m as __pageData,u as default};
